  it('sends the bare key when the key-pair passphrase is left blank', async () => {
    const user = userEvent.setup();
    mockReauth.mockResolvedValue({ ok: true });

    render(
      <AntApp>
        <ReauthModal
          connection={{ ...connection, config: { auth_type: 'key_pair' } }}
          onClose={vi.fn()}
          onDone={vi.fn()}
        />
      </AntApp>,
    );

